{
  "query": "query Login($usernameOrEmail: String!, $password: String!) { login(usernameOrEmail: $usernameOrEmail, password: $password) { message token user { _id username email created_at updated_at } } }",
  "variables": {
    "usernameOrEmail": "you@example.com",
    "password": "yourpassword"
  }
}

{
  "query": "mutation Signup($username: String!, $email: String!, $password: String!) { signup(username: $username, email: $email, password: $password) { message token user { _id username email } } }",
  "variables": {
    "username": "newuser",
    "email": "newuser@example.com",
    "password": "yourpassword"
  }
}

{
  "query": "query { getAllEmployees { _id first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }"
}

{
  "query": "query GetOne($id: ID!) { getEmployeeById(id: $id) { _id first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }",
  "variables": {
    "id": "{{employeeId}}"
  }
}

{
  "query": "query Search($designation: String, $department: String) { searchEmployees(designation: $designation, department: $department) { _id first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }",
  "variables": {
    "designation": "Developer",
    "department": "Engineering"
  }
}

{
  "query": "mutation Add($input: EmployeeInput!) { addEmployee(input: $input) { _id first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }",
  "variables": {
    "input": {
      "first_name": "Jane",
      "last_name": "Doe",
      "email": "jane.doe@example.com",
      "gender": "Female",
      "designation": "Developer",
      "salary": 75000,
      "date_of_joining": "2024-06-01T00:00:00.000Z",
      "department": "Engineering",
      "employee_photo": null
    }
  }
}

{
  "query": "mutation Update($id: ID!, $input: EmployeeInput!) { updateEmployee(id: $id, input: $input) { _id first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }",
  "variables": {
    "id": "{{employeeId}}",
    "input": {
      "first_name": "Jane",
      "last_name": "Doe",
      "email": "jane.updated@example.com",
      "gender": "Female",
      "designation": "Senior Developer",
      "salary": 82000,
      "date_of_joining": "2024-06-01T00:00:00.000Z",
      "department": "Engineering",
      "employee_photo": null
    }
  }
}
